import type { Observable, Subscription } from "rxjs";
import { map, merge, startWith, switchMap } from "rxjs";
import * as THREE from "three";

import type { Codable } from "./codable";
import type { ZenGardenObject } from "./object";
import type { PlainTextureGenerator } from "./plain-texture";
import { createPlainTextureGenerator } from "./plain-texture";
import { ZenGardenRakeStroke } from "./rake-stroke";
import type { Vector2Encoded } from "./vector2";
import { Vector2 } from "./vector2";

export type ZenGardenPlainEncoded = {
  size: Vector2Encoded;
};

const PLAIN_Z = 0;
const TILE_SIZE = 2;

export class ZenGardenPlain implements Codable<ZenGardenPlainEncoded> {
  readonly object: THREE.Mesh;
  private material: THREE.MeshStandardMaterial;
  private subscription: Subscription | null = null;
  private textureGenerator: PlainTextureGenerator | null = null;
  private pendingStrokes: ZenGardenRakeStroke[] = [];
  private _size: Vector2;

  constructor(
    encoded: ZenGardenPlainEncoded,
    private renderer: THREE.WebGLRenderer,
  ) {
    this._size = new Vector2(encoded.size);

    const geometry = new THREE.PlaneGeometry(1, 1);
    this.material = new THREE.MeshStandardMaterial({
      color: 0xd4c4a8,
      roughness: 1,
    });

    this.object = new THREE.Mesh(geometry, this.material);
    this.object.position.z = PLAIN_Z;
    this.object.receiveShadow = true;
    this.object.scale.set(this._size.x, this._size.y, 1);

    this.loadGravelTexture();
  }

  private loadGravelTexture(): void {
    const loader = new THREE.TextureLoader();
    loader.load("/textures/gravel/color.jpg", (texture) => {
      texture.wrapS = THREE.RepeatWrapping;
      texture.wrapT = THREE.RepeatWrapping;

      this.textureGenerator = createPlainTextureGenerator(
        this.renderer,
        { x: this._size.x, y: this._size.y },
        TILE_SIZE,
        texture,
      );

      this.material.map = this.textureGenerator.texture;
      this.material.needsUpdate = true;

      // Render pending strokes if any
      console.log("[PlainTexture] Initial render with", this.pendingStrokes.length, "strokes");
      this.textureGenerator.update(this.pendingStrokes);
    });
  }

  subscribeToRakeStrokes($objects: Observable<ZenGardenObject[]>): void {
    this.subscription?.unsubscribe();

    this.subscription = $objects.pipe(
      map(objects => objects.filter(o => o instanceof ZenGardenRakeStroke)),
      switchMap(strokes => {
        if (strokes.length === 0) {
          return [strokes];
        }
        return merge(...strokes.map(s => s.$changed)).pipe(
          startWith(null),
          map(() => strokes),
        );
      }),
    ).subscribe(strokes => {
      if (this.textureGenerator) {
        this.textureGenerator.update(strokes);
      } else {
        this.pendingStrokes = strokes;
      }
    });
  }

  dispose(): void {
    this.subscription?.unsubscribe();
    this.textureGenerator?.dispose();
    this.material.dispose();
  }

  get size(): Vector2 {
    return this._size.clone();
  }

  set size(value: Vector2) {
    this._size = value.clone();
    this.object.scale.set(value.x, value.y, 1);
  }

  serialize(): ZenGardenPlainEncoded {
    return {
      size: this._size.serialize(),
    };
  }
}
